52.             var nextLinkOperation = (NextLinkOperationImplementation)NextLinkOperationImplementation.Create(client.Pipeline, rehydrationToken);
53.             var operation = NextLinkOperationImplementation.Create(source, nextLinkOperation);
54.             var operationState = operation.UpdateStateAsync(async: false, default).EnsureCompleted();
55.             return new RehydrationOperation<T>(nextLinkOperation, operationState, operation, options);
56.         }
